#define STR_SIZE 256

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

#define GPU
#define TIMER

__global__ void
srad_kernel_1(
          float *E_C, 
          float *W_C, 
          float *N_C, 
          float *S_C,
          float * J_cuda, 
          float * C_cuda, 
          int cols, 
          int rows, 
          float q0sqr
) 
{
  int bx = get_block_id(0);
  int by = get_block_id(1);

  int tx = get_local_id(0);
  int ty = get_local_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
  int index_n = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + tx - cols;
  int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
  int index_w = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty - 1;
  int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;

  float n, w, e, s, jc, g2, l, num, den, qsqr, c;

  __local float temp[BLOCK_SIZE][BLOCK_SIZE];
  __local float temp_result[BLOCK_SIZE][BLOCK_SIZE];

  __local float north[BLOCK_SIZE][BLOCK_SIZE];
  __local float south[BLOCK_SIZE][BLOCK_SIZE];
  __local float  east[BLOCK_SIZE][BLOCK_SIZE];
  __local float  west[BLOCK_SIZE][BLOCK_SIZE];

  // Load North
  if (by == 0) {
      north[ty][tx] = J_cuda[BLOCK_SIZE * bx + tx]; 
  } else {
      north[ty][tx] = J_cuda[index_n]; 
  }

  // Load South
  if (by == get_num_blocks(1) - 1) {
      south[ty][tx] = J_cuda[cols * BLOCK_SIZE * (get_num_blocks(1) - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
  } else {
      south[ty][tx] = J_cuda[index_s];
  }

  barrier(CLK_LOCAL_MEM_FENCE);

  // Load West
  if (bx == 0) {
      west[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + cols * ty]; 
  } else {
      west[ty][tx] = J_cuda[index_w];
  }

  // Load East
  if (bx == get_num_blocks(0) - 1) {
      east[ty][tx] = J_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (get_num_blocks(0) - 1) + cols * ty + BLOCK_SIZE - 1];
  } else {
      east[ty][tx] = J_cuda[index_e];
  }

  barrier(CLK_LOCAL_MEM_FENCE);

  temp[ty][tx] = J_cuda[index];

  barrier(CLK_LOCAL_MEM_FENCE);

  jc = temp[ty][tx];

  // Calculate differences based on position in block
  if (ty == 0 && tx == 0) { 
      n = north[ty][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = west[ty][tx] - jc; 
      e = temp[ty][tx+1] - jc;
  }	    
  else if (ty == 0 && tx == BLOCK_SIZE-1) { 
      n = north[ty][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = east[ty][tx] - jc;
  }
  else if (ty == BLOCK_SIZE -1 && tx == BLOCK_SIZE - 1) { 
      n = temp[ty-1][tx] - jc;
      s = south[ty][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = east[ty][tx] - jc;
  }
  else if (ty == BLOCK_SIZE -1 && tx == 0) {
      n = temp[ty-1][tx] - jc;
      s = south[ty][tx] - jc;
      w = west[ty][tx] - jc; 
      e = temp[ty][tx+1] - jc;
  }
  else if (ty == 0) { 
      n = north[ty][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = temp[ty][tx+1] - jc;
  }
  else if (tx == BLOCK_SIZE -1) { 
      n = temp[ty-1][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = east[ty][tx] - jc;
  }
  else if (ty == BLOCK_SIZE -1) { 
      n = temp[ty-1][tx] - jc;
      s = south[ty][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = temp[ty][tx+1] - jc;
  }
  else if (tx == 0) { 
      n = temp[ty-1][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = west[ty][tx] - jc; 
      e = temp[ty][tx+1] - jc;
  }
  else {  
      n = temp[ty-1][tx] - jc;
      s = temp[ty+1][tx] - jc;
      w = temp[ty][tx-1] - jc; 
      e = temp[ty][tx+1] - jc;
  }

  g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
  l = (n + s + w + e) / jc;

  num = (0.5f * g2) - ((1.0f/16.0f) * (l * l));
  den = 1.0f + (0.25f * l);
  qsqr = num / (den * den);

  den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
  c = 1.0f / (1.0f + den);

  if (c < 0.0f) {
      temp_result[ty][tx] = 0.0f;
  } else if (c > 1.0f) {
      temp_result[ty][tx] = 1.0f;
  } else {
      temp_result[ty][tx] = c;
  }

  barrier(CLK_LOCAL_MEM_FENCE);

  C_cuda[index] = temp_result[ty][tx];
  E_C[index] = e;
  W_C[index] = w;
  S_C[index] = s;
  N_C[index] = n;
}

__global__ void
srad_kernel_2(
          float *E_C, 
          float *W_C, 
          float *N_C, 
          float *S_C,	
          float * J_cuda, 
          float * C_cuda, 
          int cols, 
          int rows, 
          float lambda,
          float q0sqr
) 
{
  int bx = get_block_id(0);
  int by = get_block_id(1);

  int tx = get_local_id(0);
  int ty = get_local_id(1);

  int index   = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + tx;
  int index_s = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * BLOCK_SIZE + tx;
  int index_e = cols * BLOCK_SIZE * by + BLOCK_SIZE * bx + cols * ty + BLOCK_SIZE;

  float cc, cn, cs, ce, cw, d_sum;

  __local float south_c[BLOCK_SIZE][BLOCK_SIZE];
  __local float east_c[BLOCK_SIZE][BLOCK_SIZE];
  __local float c_cuda_temp[BLOCK_SIZE][BLOCK_SIZE];
  __local float c_cuda_result[BLOCK_SIZE][BLOCK_SIZE];
  __local float temp[BLOCK_SIZE][BLOCK_SIZE];

  temp[ty][tx] = J_cuda[index];
  barrier(CLK_LOCAL_MEM_FENCE);

  // Load South C
  if (by == get_num_blocks(1) - 1) {
      south_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * (get_num_blocks(1) - 1) + BLOCK_SIZE * bx + cols * (BLOCK_SIZE - 1) + tx];
  } else {
      south_c[ty][tx] = C_cuda[index_s];
  }
  barrier(CLK_LOCAL_MEM_FENCE);

  // Load East C
  if (bx == get_num_blocks(0) - 1) {
      east_c[ty][tx] = C_cuda[cols * BLOCK_SIZE * by + BLOCK_SIZE * (get_num_blocks(0) - 1) + cols * ty + BLOCK_SIZE - 1];
  } else {
      east_c[ty][tx] = C_cuda[index_e];
  }
  barrier(CLK_LOCAL_MEM_FENCE);

  c_cuda_temp[ty][tx] = C_cuda[index];
  barrier(CLK_LOCAL_MEM_FENCE);

  cc = c_cuda_temp[ty][tx];

  if (ty == BLOCK_SIZE - 1 && tx == BLOCK_SIZE - 1) { 
      cn = cc;
      cs = south_c[ty][tx];
      cw = cc; 
      ce = east_c[ty][tx];
  } 
  else if (tx == BLOCK_SIZE - 1) { 
      cn = cc;
      cs = c_cuda_temp[ty+1][tx];
      cw = cc; 
      ce = east_c[ty][tx];
  }
  else if (ty == BLOCK_SIZE - 1) { 
      cn = cc;
      cs = south_c[ty][tx];
      cw = cc; 
      ce = c_cuda_temp[ty][tx+1];
  }
  else { 
      cn = cc;
      cs = c_cuda_temp[ty+1][tx];
      cw = cc; 
      ce = c_cuda_temp[ty][tx+1];
  }

  d_sum = cn * N_C[index] + cs * S_C[index] + cw * W_C[index] + ce * E_C[index];

  c_cuda_result[ty][tx] = temp[ty][tx] + 0.25f * lambda * d_sum;

  barrier(CLK_LOCAL_MEM_FENCE);

  J_cuda[index] = c_cuda_result[ty][tx];
}
